// SPDX-License-Identifier: MIT
pragma solidity ^0.8.21;

contract VaccineRegistry {

    enum Status { 
        UploadedByManufacturer, 
        VerifiedByCDC, 
        ApprovedByRegulator 
    }

    struct VaccineRecord {
        string merkleRoot;
        string datasetCID;
        string proofCID;
        Status status;
        uint256 timestamp;
    }

    mapping(string => VaccineRecord) public records;

    address public manufacturer;
    address public cdc;
    address public regulator;

    constructor(address _manufacturer, address _cdc, address _regulator){
        manufacturer = _manufacturer;
        cdc = _cdc;
        regulator = _regulator;
    }

    // -------------------------------
    // 1️⃣ Manufacturer uploads data
    // -------------------------------
    function uploadByManufacturer(
        string memory batchId,
        string memory merkleRoot,
        string memory datasetCID,
        string memory proofCID
    ) public {
        require(msg.sender == manufacturer, "Only Manufacturer allowed");

        records[batchId] = VaccineRecord({
            merkleRoot: merkleRoot,
            datasetCID: datasetCID,
            proofCID: proofCID,
            status: Status.UploadedByManufacturer,
            timestamp: block.timestamp
        });
    }

    // -------------------------------
    // 2️⃣ CDC verifies batch
    // -------------------------------
    function verifyByCDC(string memory batchId) public {
        require(msg.sender == cdc, "Only CDC allowed");
        require(records[batchId].timestamp != 0, "Batch not found");

        records[batchId].status = Status.VerifiedByCDC;
    }

    // -------------------------------
    // 3️⃣ Regulator approves final batch
    // -------------------------------
    function approveByRegulator(string memory batchId) public {
        require(msg.sender == regulator, "Only regulator allowed");
        require(records[batchId].timestamp != 0, "Batch not found");
        require(records[batchId].status == Status.VerifiedByCDC, "Must be CDC verified");

        records[batchId].status = Status.ApprovedByRegulator;
    }

    // -------------------------------
    // Getter for entire record
    // -------------------------------
    function getRecord(string memory batchId)
        public view
        returns (VaccineRecord memory)
    {
        return records[batchId];
    }
}
